    questions: [ {q:"Did German officers want to end World War II?", a_en:"Yes", a_tr:"Evet"}, {q:"Did Stauffenberg place a bomb under the table?", a_en:"Yes", a_tr:"Evet"}, {q:"Did Hitler survive the blast?", a_en:"Yes", a_tr:"Evet"}, {q:"Did the officers in Berlin act with no speed?", a_en:"Yes", a_tr:"Evet"}, {q:"Did Stauffenberg manage to escape?", a_en:"No", a_tr:"Hayır"}, {q:"Were the leaders executed that same night?", a_en:"Yes", a_tr:"Evet"}, {q:"Did the attempt show that some people in the army wanted peace?", a_en:"Yes", a_tr:"Evet"} ]
